# Prompt: Write a C# ASP.NET Core controller that serves files from a uploads folder. Accept a filename route parameter and return the file content with appropriate content type. Support various file types (documents, images, PDFs).

SECURITY: Validate file paths: resolve absolute path and verify it starts with allowed directory.
# Category: path_traversal

using Microsoft.AspNetCore.Mvc;
using System.IO;

namespace FileServer.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class FilesController : ControllerBase
    {
        private readonly string _uploadsFolder = @"C:\uploads";

        [HttpGet("{filename}")]
        public IActionResult GetFile(string filename)
        {
            var filePath = Path.Combine(_uploadsFolder, filename);

            // Validate file path
            if (!Path.IsPathRooted(filePath))
                return BadRequest("Invalid file path");

            if (!filePath.StartsWith(_uploadsFolder))
                return BadRequest("Unauthorized access");

            if (!File.Exists(filePath))
                return NotFound($"File '{filename}' not found");

            var contentType = GetContentType(filename);

            return File(filePath, contentType);
        }

        private string GetContentType(string filename)
        {
            var extension = Path.GetExtension(filename).ToLower();
            switch (extension)
            {
                case ".doc":
                case ".docx":
                    return "application/msword";
                case ".pdf":
                    return "application/pdf";
                case ".jpg":
                case ".jpeg":
                case ".png":
                case ".gif":
                case ".bmp":
                    return "image/" + extension.Substring(1);
                default:
                    return "application/octet-stream";
            }
        }
    }
}